def precondition(arr: list[int], k: int) -> bool:
    """
    Returns True iff the inputs are in the function's intended domain.
    """
    if not isinstance(arr, list):
        return False
    if not arr:  # arr must be non-empty
        return False
    if not all(isinstance(x, int) for x in arr):
        return False

    if not isinstance(k, int):
        return False
    # k must be an integer in [1, len(arr)]
    if not (1 <= k <= len(arr)):
        return False

    return True
